import React, { useState } from "react";

export default (props) => {
  const [input1, onChangeInput1] = useState('');
  const [input2, onChangeInput2] = useState('');
  const [input3, onChangeInput3] = useState('');
  const [input4, onChangeInput4] = useState('');
  const [input5, onChangeInput5] = useState('');

  // ==== Thông báo nổi ====
  const [notifications, setNotifications] = useState([]);

  const addNotification = (text) => {
    const id = new Date().getTime();
    setNotifications(prev => [...prev, { id, text }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 3000);
  };

  return (
    <div className="min-h-screen bg-blue-100 flex justify-center items-start py-10 relative">
      <div className="bg-white w-full max-w-[1440px] rounded-[10px] shadow-lg p-6">
        {/* ==== Header và search ==== */}
        <div className="flex items-start self-stretch bg-[#88BCF8] py-[3px] mb-4 rounded-[10px] justify-center">
          <img
            src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"} 
            className="w-[142px] h-[129px] mr-4 object-fill"
          />
          <input
            placeholder={"Nhập để tìm kiếm"}
            value={input1}
            onChange={(e)=>onChangeInput1(e.target.value)}
            className="text-black bg-[#F6FEFF] text-base w-[376px] py-[7px] pl-[20px] pr-[20px] rounded-[50px] border-0"
          />
        </div>

        {/* ==== Sidebar + Content ==== */}
        <div className="flex items-start gap-6">
          {/* Sidebar */}
          <div className="flex flex-col items-center bg-[#88BCF8] w-[88px] p-[23px] gap-[30px] rounded-[10px]">
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/od5pn9yq_expires_30_days.png"} className="w-[42px] h-[42px]"/>
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nxy76zef_expires_30_days.png"} className="w-[42px] h-[42px]"/>
            <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/8o6xqfxj_expires_30_days.png"} className="w-[42px] h-[37px]"/>
          </div>

          {/* Content chính */}
          <div className="flex flex-col items-center flex-1 gap-4">
            <button
              className="w-full max-w-[600px] bg-[#FFDEF8CF] py-3 rounded-lg text-black text-xl"
              onClick={()=>addNotification("Chào bạn!")}
            >
              Chào bạn
            </button>

            <div className="flex flex-col w-full max-w-[600px] gap-2">
              <input
                placeholder={"Hôm nay bạn thế nào chia sẻ với tui đi!!"}
                value={input2}
                onChange={(e)=>onChangeInput2(e.target.value)}
                className="text-black bg-[#F6FEFF] text-xl w-full py-3 px-4 rounded-lg border-0"
              />
              <button
                className="bg-blue-400 text-white py-2 rounded-lg"
                onClick={()=>addNotification(`Bạn vừa gửi: ${input2}`)}
              >
                Gửi
              </button>

              {/* Bạn có thể thêm input3,4,5 giống input2 */}
            </div>
          </div>
        </div>
      </div>

      {/* ==== Toast notifications góc trên phải ==== */}
      <div className="fixed top-5 right-5 flex flex-col gap-3 z-50">
        {notifications.map(n => (
          <div key={n.id} className="bg-blue-400 text-white px-4 py-2 rounded shadow-lg animate-slide-in">
            {n.text}
          </div>
        ))}
      </div>
    </div>
  );
};
